SELECT Item.[vendor no_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Transfer Line].[Item No_] AS Article, Item.[Description 2] AS Description, [Transfer Line].[Constant Variable Code] AS Color, [Transfer Line].[Assortment Code], Sum(IIf(Val([transfer line.quantity])>0,Val([Transfer Line.No_ of Pairs])/Val([transfer line.quantity])*(Val([quantity shipped])-Val([quantity received])),0)) AS PairsTravelling, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_) INNER JOIN Item ON [Transfer Line].[Item No_] = Item.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY Item.[vendor no_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Transfer Line].[Item No_], Item.[Description 2], [Transfer Line].[Constant Variable Code], [Transfer Line].[Assortment Code], [Transfer Line].[item Type], Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name
HAVING (((Sum(IIf(Val([transfer line.quantity])>0,Val([Transfer Line.No_ of Pairs])/Val([transfer line.quantity])*(Val([quantity shipped])-Val([quantity received])),0)))<>0) AND (([Transfer Line].[item Type])=19 Or ([Transfer Line].[item Type])=20) AND ((Item.[Advertising Material])=0));

